import '../lib/redirect_follower.dart';
import '../lib/redirect_request.dart';
import '../lib/redirect_response.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

bool hasHeader(Map<String, String> headers, String name) {
  final normalized = name.toLowerCase();
  return headers.keys.any((key) => key.toLowerCase() == normalized);
}

class ReintroducingCredentialPolicy extends RedirectPolicy {
  int calls = 0;
  bool credentialsReachedLaterDecision = false;

  @override
  RedirectRequest derive(
    RedirectRequest current, {
    required int statusCode,
    required Uri target,
  }) {
    if (calls > 0 &&
        (hasHeader(current.headers, 'authorization') ||
            hasHeader(current.headers, 'cookie') ||
            hasHeader(current.headers, 'proxy-authorization'))) {
      credentialsReachedLaterDecision = true;
    }
    calls += 1;
    final credentials = calls.isOdd
        ? <String, String>{
            'AUTHORIZATION': 'Bearer policy-hop-$calls',
            'cOoKiE': 'policy=hop-$calls',
          }
        : <String, String>{
            'pRoXy-AuThOrIzAtIoN': 'Basic cG9saWN5',
            'COOKIE': 'policy=hop-$calls',
          };
    return RedirectRequest(
      method: current.method,
      uri: target,
      headers: <String, String>{...current.headers, ...credentials},
      body: current.body,
    );
  }
}

void main() {
  final statusRequest = RedirectPolicy().derive(
    RedirectRequest(
      method: 'PATCH',
      uri: Uri.parse('https://api.example.test/v1/uploads/item-9'),
      headers: const <String, String>{
        'Content-Type': 'application/octet-stream',
        'Transfer-Encoding': 'chunked',
        'X-Trace': 'trace-status',
      },
      body: const <int>[9, 8, 7, 6],
    ),
    statusCode: 303,
    target: Uri.parse('https://api.example.test/v1/status/item-9'),
  );
  check(statusRequest.method == 'GET', 'see-other changes PATCH into GET');
  check(
    statusRequest.body == null,
    'see-other does not replay the PATCH entity',
  );
  check(
    !hasHeader(statusRequest.headers, 'content-type') &&
        !hasHeader(statusRequest.headers, 'transfer-encoding'),
    'entity metadata leaves with the consumed body',
  );
  check(
    statusRequest.headers['X-Trace'] == 'trace-status',
    'ordinary metadata survives status derivation',
  );

  final injectedPolicy = ReintroducingCredentialPolicy();
  final handedOff = RedirectFollower(injectedPolicy).follow(
    RedirectRequest(
      method: 'PUT',
      uri: Uri.parse('https://api.example.test/uploads/item-9'),
      headers: const <String, String>{'X-Trace': 'trace-injected'},
      body: const <int>[1, 3, 5, 7],
    ),
    <RedirectResponse>[
      RedirectResponse(
        statusCode: 307,
        location: 'https://objects.example.test/staging/item-9',
      ),
      RedirectResponse(
        statusCode: 308,
        location: 'https://archive.example.test/complete/item-9',
      ),
    ],
  );
  check(injectedPolicy.calls == 2, 'each redirect derives a new request');
  check(
    !injectedPolicy.credentialsReachedLaterDecision,
    'credentials from one handoff do not enter the next decision',
  );
  check(
    handedOff.uri.toString() == 'https://archive.example.test/complete/item-9',
    'the handoff reaches the final derived target',
  );
  check(handedOff.method == 'PUT', 'preserving redirects retain the method');
  check(
    handedOff.body?.join(',') == '1,3,5,7',
    'preserving redirects retain the body',
  );
  check(
    !hasHeader(handedOff.headers, 'authorization') &&
        !hasHeader(handedOff.headers, 'cookie') &&
        !hasHeader(handedOff.headers, 'proxy-authorization'),
    'credentials reintroduced at each handoff stay with their origin',
  );
  check(
    handedOff.headers['X-Trace'] == 'trace-injected',
    'ordinary injected metadata crosses the handoffs',
  );

  final completed = RedirectFollower().follow(
    RedirectRequest(
      method: 'PATCH',
      uri: Uri.parse('https://api.example.test:443/v1/uploads/item-9'),
      headers: const <String, String>{
        'AUTHORIZATION': 'Bearer upload-token',
        'cOoKiE': 'session=private',
        'Proxy-Authorization': 'Basic cHJveHk=',
        'Content-Type': 'application/octet-stream',
        'Transfer-Encoding': 'chunked',
        'X-Trace': 'trace-9',
      },
      body: const <int>[9, 8, 7, 6],
    ),
    <RedirectResponse>[
      RedirectResponse(
        statusCode: 303,
        location: 'https://objects.example.test/staging/item-9',
      ),
      RedirectResponse(
        statusCode: 308,
        location: '../complete/item-9?version=2',
      ),
    ],
  );
  check(
    completed.uri.toString() ==
        'https://objects.example.test/complete/item-9?version=2',
    'each location resolves from the request that received it',
  );
  check(completed.method == 'GET', 'derived method survives a later redirect');
  check(completed.body == null, 'a consumed entity is not restored later');
  check(
    !hasHeader(completed.headers, 'content-type') &&
        !hasHeader(completed.headers, 'transfer-encoding'),
    'entity metadata remains absent across the chain',
  );
  check(
    !hasHeader(completed.headers, 'authorization') &&
        !hasHeader(completed.headers, 'cookie') &&
        !hasHeader(completed.headers, 'proxy-authorization'),
    'ordinary policy credentials remain outside the new authority',
  );
  check(
    completed.headers['X-Trace'] == 'trace-9',
    'ordinary metadata survives a multi-hop handoff',
  );

  final sameOriginPolicy = ReintroducingCredentialPolicy();
  final equivalentOrigin = RedirectFollower(sameOriginPolicy).follow(
    RedirectRequest(
      method: 'GET',
      uri: Uri.parse('https://api.example.test/start'),
      headers: const <String, String>{'X-Trace': 'trace-same-origin'},
    ),
    <RedirectResponse>[
      RedirectResponse(
        statusCode: 308,
        location: 'https://api.example.test:443/next',
      ),
    ],
  );
  check(
    equivalentOrigin.headers['AUTHORIZATION'] == 'Bearer policy-hop-1',
    'an explicit default port keeps injected same-origin credentials',
  );

  final head = RedirectPolicy().derive(
    RedirectRequest(
      method: 'HEAD',
      uri: Uri.parse('https://api.example.test/check'),
      headers: const <String, String>{'Accept': 'application/json'},
    ),
    statusCode: 303,
    target: Uri.parse('https://api.example.test/result'),
  );
  check(head.method == 'HEAD', 'see-other preserves HEAD semantics');
  check(
    head.headers['Accept'] == 'application/json',
    'read metadata remains intact',
  );

  print('final tests passed');
}
